var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"며칠 뒤","JPN":"数日後","ENG":"A few days later","TWN":"幾天後","SCN":"几天后","DEU":"A few days later","FRA":"A few days later"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"관리국 제4 수색전대 <color=#ffd34c>야크샤</color> 정기 회의","JPN":"管理局第4捜索戦隊<color=#ffd34c>ヤクシャー</color>定期会議","ENG":"Administration 4th Recon Division <color=#ffd34c>Yaksha</color> Regular Meeting","TWN":"管理局第4偵察戰隊<color=#ffd34c>夜叉</color>定期會議","SCN":"管理局第4侦察战队<color=#ffd34c>夜叉</color>定期会议","DEU":"Administration 4th Recon Division <color=#ffd34c>Yaksha</color> Regular Meeting","FRA":"Administration 4th Recon Division <color=#ffd34c>Yaksha</color> Regular Meeting"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":" ……아하하. 뭐, 이런저런 사정이 있었던 거지.","JPN":" ……あはは。まあ、いろいろあったんだ。","ENG":"...Ah hah hah. Well, there was a lot going on.","TWN":"……哈哈。嗯，因為某種原因……"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":" 그래도 4종 침식체랑 모더레이터가 동시에 나타났는데 시설피해도 최소한으로 줄였고.","JPN":" でも第4種侵食体とモデレーターが同時に現われたのに、施設の被害も最小限に抑えたし。","ENG":"But even with a Category 4 C.O. and a Moderator appearing simultaneously, we kept the damage to a minimum.","TWN":"雖然4類侵蝕體和仲裁者同時出現，但傷害被降到了最低。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":" 사상자는 없었다고. 이 정도면 꽤 선방한 거 아니야?","JPN":" 死傷者はいなかったんだから、頑張ったほうさ。","ENG":"No casualties, so didn't we do a pretty good job?","TWN":"沒有人員傷亡。不是一個很好的結果嗎？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":" 다들 그렇게 생각하는 거 맞지……? 아하하……?","JPN":" みんなそう思ってるよな……？　あはは……？","ENG":"That's what everyone's thinking, right...? Ah hah hah...?","TWN":"大家都是這麼想的吧……？哈哈……？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":" 으으!! 괜찮기는 뭐가 괜찮습니까요!!","JPN":" うう！！　全然大丈夫じゃないでやんすよ！！","ENG":"Errgh!! No, everything's not okay!!","TWN":"啊！！怎麼可能沒事！！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":" 피투성이가 된 채로 기지에 복귀해서 모더레이터의 잔해를 분석해달라고 할 때는 언제고!","JPN":" 血まみれで基地に復帰して、モデレーターの残骸を分析しろって言ったくせに！","ENG":"You returned covered in blood, then asked me to analyze the Moderator's remains!","TWN":"當你渾身是血回到基地並要求分析仲裁者的殘骸的時候！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":" 야이! 쪽팔리게시리!","JPN":" おい！　恥ずかしいだろう！","ENG":"Hey! Why are you trying to shame me?","TWN":"喂！哪有那麼丟人！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":" 그 정도는 아니었거든? 그냥 조금 긁힌 정도라니깐?","JPN":" そこまでじゃなかったよ。ちょっとしたかすり傷さ。","ENG":"Plus, it wasn't that bad! I just got a tiny scratch, that's all!","TWN":"沒那麼糟糕吧？就是一點點皮肉傷。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":" 자꾸 지휘부의 작전 지시를 어기고 단독 행동을 하면 어떻게 합니까요!","JPN":" 何回も司令部の作戦指示を無視して、単独行動するなんてありえないでやんす！","ENG":"And why do you keep ignoring the Headquarters' orders, and acting on your own?!","TWN":"如你總是這樣不聽作戰指揮，單獨行動要怎麼辦！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":" 가뜩이나 큰 작전을 앞두고 있어서 다들 긴장하고 있는데.","JPN":" ただでさえ大作戦を控えて、みんな緊張してるってのに。","ENG":"Didn't you notice how everyone was on edge because of the upcoming huge operation?","TWN":"本來面臨大型作戰，大家都很緊張。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":" 아무튼 작전이 크든 작든 그런 게 뭐가 중요해?","JPN":" 大作戦でも小作戦でも、そんなのは重要じゃないさ。","ENG":"What does it matter if the operation is big or small?","TWN":"和作戰規模大小有什麼關係？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":" 전우들의 목숨이 달린 일이었어, 하마터면 큰 일 날 뻔 했다구!! 진짜야!!","JPN":" 戦友たちの命がかかってたんだ。危うく大惨事になるところだったんだぞ！！　嘘じゃない！！","ENG":"Comrades' lives were on the line. They could've died, you know!!","TWN":"這是關乎同伴生命的大事，差點就出事了呢！！真的！！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":" …….","JPN":" ……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":" 앨리스, 쥐스틴은 널 걱정해서 하는 말이잖아.","JPN":" アリス、ジュスティーヌはあなたを心配して言ってるのでしょう。","ENG":"Alice, Justine is saying those things because she was worried about you.","TWN":"艾莉絲，潔絲婷這麼說是因為她擔心你。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":" ……알고 있어.","JPN":" ……わかってる。","ENG":"...I know.","TWN":"……我知道。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":" 하지만 말했잖아. 다시는 내 앞에서 아무도 죽게 내버려두지 않겠다고.","JPN":" でも、言っただろう？　二度とアタシの前では誰も死なせない。","ENG":"But I told you once before. I'm not going to allow anyone to die on my watch anymore.","TWN":"但我說過了。我不會再讓任何人死在我面前。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":" 그러기 위한 카운터 능력이고, 그러기 위한 전대장 자리야.","JPN":" そのためのカウンター能力で、そのための戦隊長だ。","ENG":"That's what my Counter ability and my position as Commander of this division is for.","TWN":"為此，我有了制裁者的能力，為此，我成為了戰隊長。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":" 누가 뭐래도 내가 전대장에 있는 한, 그 각오를 저버리는 일은 없을 테니까.","JPN":" 誰が何と言おうとも、アタシが戦隊長である以上、その覚悟は揺らがない。","ENG":"No matter what anyone says, as long as I'm the Commander, I'll never let my determination go.","TWN":"不管別人怎麼說，只要我是戰隊長，我就不會背叛這個決心。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":" ……후우.","JPN":" ……ふう。","ENG":"...*Sigh*","TWN":"……呼。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":" 그래~ 그래~ 알겠어.","JPN":" はいはい。わかったよ。","ENG":"Okay, okay. I understand.","TWN":"好～好～我明白了。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":" 그게 우두머리로서의 네 선택이라면 전대원인 우리가 그걸 존중하는 게 맞겠지.","JPN":" それがリーダーとしてのあなたの選択なら、戦隊員の私たちはそれを尊重するべきだもの。","ENG":"If that is what you've decided as our leader, then we'll all have to respect it.","TWN":"如果這是你作為戰隊長的選擇，我們作為戰隊的成員就應該尊重。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":" ……어쩐지 비꼬는 거 같은데?","JPN":" ……なんか皮肉ってないか？","ENG":"...Why does that sound somewhat sarcastic?","TWN":"……怎麼感覺你是在諷刺我呢……？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":" 어쨌든 앨리스 말대로 이상한 점이 있다고 생각해.","JPN":" とにかくアリスの言葉どおり、なんだか不審だわ。","ENG":"Anyway, I also think there's something strange about it, like Alice said.","TWN":"總之，正如艾莉絲所說，我覺得這件事有些蹊蹺。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":" 정보 오염된 모더레이터가 특정 대상을 노린다는 이야기는 들어본 적 없거든.","JPN":" 情報が汚染されたモデレーターが特定対象を狙うなんて、聞いたことがないの。","ENG":"I've never heard of a data-corrupted Moderator specifically targeting something.","TWN":"我從未聽說過有資訊污染的仲裁者會去針對特定目標。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":" 작전 구역에서 모더레이터와 함께 나타났던 정체불명의 휴머노이드 타입도 그렇고.","JPN":" 作戦区域でモデレーターと一緒に現われた正体不明のヒューマノイドタイプもそうだし。","ENG":"And also that unidentified humanoid-type that appeared along with the Moderator in the operation zone.","TWN":"與仲裁者一起出現在作戰區域的不明類人類也是如此。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};